INSERT INTO tenant_focus_group_messages (id, group_id, tenant_id, member_id, body, created_at) VALUES ('bf10aacc-c2ba-5bf8-85e2-c9ee8cd66c55', '86cbb4b3-614c-57c8-91aa-a0cc06fc6978', '82ad796a-ac3a-527b-b6d1-8ffd5f63c8cc', '5740b573-7806-5b48-be2f-64543b96403f', 'Anyone switched to compostable packaging that actually holds up? Ours keeps splitting in the cool room.', NOW() - INTERVAL '1080 minutes') ON CONFLICT (id) DO UPDATE SET body = EXCLUDED.body, created_at = EXCLUDED.created_at;
