INSERT INTO tenant_focus_group_messages (id, group_id, tenant_id, member_id, body, created_at) VALUES ('dee5b7ac-2c4e-59d1-b101-36fb2be91ee6', '86cbb4b3-614c-57c8-91aa-a0cc06fc6978', '82ad796a-ac3a-527b-b6d1-8ffd5f63c8cc', '5740b573-7806-5b48-be2f-64543b96403f', 'Legend, thanks. Will flick you a message.', NOW() - INTERVAL '934 minutes') ON CONFLICT (id) DO UPDATE SET body = EXCLUDED.body, created_at = EXCLUDED.created_at;
INSERT INTO tenant_focus_group_messages (id, group_id, tenant_id, member_id, body, created_at) VALUES ('c22a00d9-bfa3-546e-912c-c841cdd658b8', '86cbb4b3-614c-57c8-91aa-a0cc06fc6978', '82ad796a-ac3a-527b-b6d1-8ffd5f63c8cc', '3e209a34-2080-56b6-aa83-41621b3be9a1', 'Horizon Solar quoted us last week. 6.6kW system, payback under 4 years at our usage. Glad to compare notes.', NOW() - INTERVAL '810 minutes') ON CONFLICT (id) DO UPDATE SET body = EXCLUDED.body, created_at = EXCLUDED.created_at;
INSERT INTO tenant_focus_group_messages (id, group_id, tenant_id, member_id, body, created_at) VALUES ('e1f4702f-c581-53bc-83bb-c0d50cae4400', '86cbb4b3-614c-57c8-91aa-a0cc06fc6978', '82ad796a-ac3a-527b-b6d1-8ffd5f63c8cc', '7e780e4e-92ae-543f-bb53-86e01ba28637', 'We went solar in March and the difference on the last bill was real. Wish we''d done it sooner.', NOW() - INTERVAL '737 minutes') ON CONFLICT (id) DO UPDATE SET body = EXCLUDED.body, created_at = EXCLUDED.created_at;
